SELECT users.name, orders.id
FROM users
INNER JOIN orders ON users.id = orders.user_id;

const users = [{id: 1, name: 'Alice'}];
const orders = [{user_id: 1, amount: 100}];
const inner = users.filter(u => orders.some(o => o.user_id === u.id));
console.log(inner);

List<User> users = Arrays.asList(new User(1, "Alice"));
List<Order> orders = Arrays.asList(new Order(1, 100));
List<User> inner = users.stream()
  .filter(u -> orders.stream().anyMatch(o -> o.userId == u.id))
  .collect(Collectors.toList());
